import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"Integración del Ecosistema y Alineación de Sponsors","description":"","frontmatter":{},"headers":[],"relativePath":"es/docs/sponsors.md","filePath":"es/docs/sponsors.md"}'),s={name:"es/docs/sponsors.md"};function n(r,e,l,c,d,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="integracion-del-ecosistema-y-alineacion-de-sponsors" tabindex="-1">Integración del Ecosistema y Alineación de Sponsors <a class="header-anchor" href="#integracion-del-ecosistema-y-alineacion-de-sponsors" aria-label="Permalink to &quot;Integración del Ecosistema y Alineación de Sponsors&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Traducción Pendiente</p><p>Este documento aún está en Inglés. La traducción al Español estará disponible pronto.</p></div><h2 id="_1-executive-summary" tabindex="-1">1. Executive Summary <a class="header-anchor" href="#_1-executive-summary" aria-label="Permalink to &quot;1. Executive Summary&quot;">​</a></h2><p>xB77 is designed as a modular aggregator of the most advanced technologies in the Solana and ZK ecosystems. Our goal is to demonstrate that privacy is not a niche requirement but a fundamental prerequisite for the institutional adoption of autonomous agents.</p><h2 id="_2-strategic-integration-by-sponsor" tabindex="-1">2. Strategic Integration by Sponsor <a class="header-anchor" href="#_2-strategic-integration-by-sponsor" aria-label="Permalink to &quot;2. Strategic Integration by Sponsor&quot;">​</a></h2><h3 id="_2-1-helius-real-time-forensics-and-observability" tabindex="-1">2.1 Helius: Real-Time Forensics and Observability <a class="header-anchor" href="#_2-1-helius-real-time-forensics-and-observability" aria-label="Permalink to &quot;2.1 Helius: Real-Time Forensics and Observability&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>FUNCTIONAL MVP (Simulated Data)</code></li><li><strong>Implementation:</strong> xB77 utilizes Helius RPCs and Webhooks as the &quot;Sensory System&quot; of the agent so it can inspect balances, market signals, and compliance risks before acting.</li><li><strong>Value Added:</strong> Instead of reactive monitoring, the agents perform proactive risk assessment; the Hub renders a Forensic Radar that visualizes destination risk scores long before transactions finalize.</li></ul><h3 id="_2-2-light-protocol-shielded-liquidity-and-compression" tabindex="-1">2.2 Light Protocol: Shielded Liquidity and Compression <a class="header-anchor" href="#_2-2-light-protocol-shielded-liquidity-and-compression" aria-label="Permalink to &quot;2.2 Light Protocol: Shielded Liquidity and Compression&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>INTEGRATION ROADMAP</code></li><li><strong>Implementation:</strong> Light Protocol acts as our primary &quot;Shielded Rail&quot; with the v3 ZK-compression architecture powering both receipt storage and operational balances.</li><li><strong>Value Added:</strong> xB77 runs &quot;Just-in-Time Shielding&quot; where funds become public only during yield harvesting or compliance reporting; the current MVP simulates the shielded state to demonstrate UX before full on-chain binding.</li></ul><h3 id="_2-3-arcium-confidential-state-and-strategic-vaults" tabindex="-1">2.3 Arcium: Confidential State and Strategic Vaults <a class="header-anchor" href="#_2-3-arcium-confidential-state-and-strategic-vaults" aria-label="Permalink to &quot;2.3 Arcium: Confidential State and Strategic Vaults&quot;">​</a></h3><ul><li><strong>Status:</strong> <code>ARCHITECTURAL PROPOSAL</code></li><li><strong>Implementation:</strong> Arcium provides encrypted vaults for strategic metadata (inventory, vendor ratings, policy state) that xB77 agents consult before making moves.</li><li><strong>Value Added:</strong> Keeps sensitive operational intelligence private even during audits, reinforcing the &quot;corporate black box&quot; narrative.</li></ul>',11)])])}